var secret = 'mypass-secret-2024';
var body = msg.payload;

if (body.secret !== secret) {
    msg.statusCode = 401;
    msg.payload = {error: 'Invalid secret'};
    node.send([null, msg]);
    return;
}

msg.action = body.action;
msg.ssid = body.ssid || 'MyPass-Guest';
msg.password = body.password || '';
msg.pass_id = body.pass_id || '';
msg.expires_at = body.expires_at || '';
msg.duration = body.duration_minutes || 60;

node.send([msg, null]);

// Build OpenWrt UCI commands to change guest WiFi password
// GL.iNet uses standard OpenWrt with UCI (Unified Configuration Interface)

var ssid = msg.ssid;
var password = msg.password;
var duration = msg.duration;

// These UCI commands change the WiFi password and restart the radio
msg.payload = [
    'uci set wireless.guest_radio0.ssid="' + ssid + '"',
    'uci set wireless.guest_radio0.key="' + password + '"',
    'uci set wireless.guest_radio0.disabled=0',
    'uci commit wireless',
    'wifi reload'
].join(' && ');

msg.schedule_minutes = duration;
node.send(msg);

// Disable guest WiFi when pass expires
msg.payload = [
    'uci set wireless.guest_radio0.disabled=1',
    'uci commit wireless',
    'wifi reload'
].join(' && ');

node.send(msg);

var body = msg.payload;
var expired = body.expired_passes || [];

if (expired.length === 0) return null;

// Disable guest WiFi for each expired pass
msg.payload = [
    'uci set wireless.guest_radio0.disabled=1',
    'uci commit wireless',
    'wifi reload'
].join(' && ');

node.log('Expiring ' + expired.length + ' passes');
return msg;
